class Solution:
    def canMakeEqual(self, nums, k):
        from collections import deque
        n = len(nums)
        start = tuple(nums)
        if len(set(start)) == 1:
            return True
        seen = {start: 0}
        q = deque([start])
        while q:
            s = q.popleft()
            d = seen[s]
            if d >= k:
                continue
            for i in range(n - 1):
                ns = list(s)
                ns[i] = -ns[i]
                ns[i + 1] = -ns[i + 1]
                ns = tuple(ns)
                if ns not in seen:
                    seen[ns] = d + 1
                    if len(set(ns)) == 1:
                        return True
                    q.append(ns)
        return False

