class Solution:
    def canMakeEqual(self, nums, k):
        n = len(nums)
        best = None
        for t in (1, -1):
            arr = [0 if x == t else 1 for x in nums]
            cnt = 0
            for i in range(n - 1):
                if arr[i] == 1:
                    arr[i] ^= 1
                    arr[i + 1] ^= 1
                    cnt += 1
            if arr[-1] == 0 and (best is None or cnt < best):
                best = cnt
        return best is not None and best <= k

