var canMakeEqual = function(nums, k) {
    const n = nums.length;
    let best = null;
    for (const t of [1, -1]) {
        const arr = nums.map(x => x === t ? 0 : 1);
        let cnt = 0;
        for (let i = 0; i < n - 1; i++) {
            if (arr[i] === 1) {
                arr[i] ^= 1;
                arr[i + 1] ^= 1;
                cnt++;
            }
        }
        if (arr[n - 1] === 0 && (best === null || cnt < best)) best = cnt;
    }
    return best !== null && best <= k;
};
